# -*- coding: utf-8 -*-
"""
deploy_datasource_phase1.py — Phase 1 地基:datasource 抽象层 (v1.0.0)
====================================================================
只安装 src/tools/datasource/ 包(base/breaker/health/router),不改 api_china。
装完做上机冒烟测试。接线到 api_china(停Baostock仍出价)是 Part B,单独部署。

用法(项目根目录):
    cd E:\\AI-tool\\Stock\\ai-hedge-fund
    poetry run python deploy_datasource_phase1.py
"""
import base64, os, sys, datetime, traceback

_DEFAULT = r"E:\AI-tool\Stock\ai-hedge-fund"
if len(sys.argv) > 1:
    ROOT = sys.argv[1]
elif os.path.isdir(os.path.join(os.getcwd(), "src", "tools")):
    ROOT = os.getcwd()
else:
    ROOT = _DEFAULT
PKG = os.path.join(ROOT, "src", "tools", "datasource")
if not os.path.isdir(os.path.join(ROOT, "src", "tools")):
    print("[FATAL] 找不到 src/tools, ROOT=" + ROOT); sys.exit(2)

print("==== 0) 目标确认 ====")
print("CWD  =", os.getcwd())
print("ROOT =", ROOT, ("  ✅ 与CWD一致" if os.path.normpath(ROOT)==os.path.normpath(os.getcwd()) else "  ⚠️ 与CWD不同!"))

FILES = {
    "__init__.py": "",
    "base.py": "",
    "breaker.py": "",
    "health.py": "",
    "router.py": ""
}

print("\n==== 1) 写入 datasource 包 ====")
os.makedirs(PKG, exist_ok=True)
for name, b in FILES.items():
    path = os.path.join(PKG, name)
    open(path, "w", encoding="utf-8", newline="\n").write(base64.b64decode(b).decode("utf-8"))
    print("  写入 datasource/%s (%d bytes)" % (name, os.path.getsize(path)))

print("\n==== 2) 上机冒烟测试 ====")
sys.path.insert(0, ROOT)
try:
    from src.tools.datasource import (FieldGroup, CallableProvider,
                                      CircuitBreaker, HealthReporter, DataSourceRouter)
    from src.tools.datasource.base import TIER_A, TIER_C
    print("import datasource: OK")

    # 造两个假源:flaky(抛异常) + backup(正常),验证失效转移 + 熔断
    calls = []
    def flaky(norm, **kw): calls.append("flaky"); raise RuntimeError("flaky down")
    def backup(norm, **kw): calls.append("backup"); return [{"src":"backup","norm":norm}]

    cb = CircuitBreaker(fail_threshold=2, open_seconds=300)
    hr = HealthReporter(jsonl_path=None)
    r = DataSourceRouter(breaker=cb, health=hr,
                         chains={FieldGroup.PRICE: ["flaky", "backup"]})
    r.register(CallableProvider("flaky", TIER_A, [FieldGroup.PRICE], {"prices": flaky}))
    r.register(CallableProvider("backup", TIER_C, [FieldGroup.PRICE], {"prices": backup}))

    data, src = r.resolve(FieldGroup.PRICE, norm="600519.SH", start="a", end="b")
    print("  resolve#1 → src=%s data=%s (期望 backup)" % (src, data))
    r.resolve(FieldGroup.PRICE, norm="x")  # flaky 第2次失败 → 熔断
    print("  flaky 熔断状态:", cb.state_of("flaky"), "(期望 open)")
    calls.clear()
    r.resolve(FieldGroup.PRICE, norm="x")
    print("  熔断后是否跳过 flaky:", "flaky" not in calls, "(期望 True)")
    print("  status:", r.status())

    ok = (src == "backup" and cb.state_of("flaky") == "open" and "flaky" not in calls)
    print("\n  冒烟结果:", "✅ PASS" if ok else "❌ FAIL")
except Exception:
    print("[冒烟异常]\n" + traceback.format_exc())

print("\n==== 完成 ====")
print("Phase 1 地基已就位。下一步 Part B:把 Router 接进 api_china(停Baostock仍出价)。")
print(">>> 把上面输出贴回 <<<")
